const NL = String.fromCharCode(10);
const items = $input.all();
const parts = [];
for (let i = 0; i < items.length; i++) {
  const bin = items[i].binary || {};
  const key = Object.keys(bin)[0];
  let txt = "";
  if (key) {
    try { txt = (await this.helpers.getBinaryDataBuffer(i, key)).toString("utf8"); }
    catch (e) { txt = Buffer.from(bin[key].data || "", "base64").toString("utf8"); }
  }
  const name = (bin[key] && bin[key].fileName) || ("paper-" + i);
  parts.push({ name: name, txt: txt });
}
parts.sort(function(a, b){ return a.name.localeCompare(b.name); });
const sep = NL + NL + "---" + NL + NL;
const header = "# 文献精读报告" + NL + NL + "生成时间：" + $now.toISO() + NL + NL + "共 " + parts.length + " 篇文献" + sep;
const reportMarkdown = header + parts.map(function(p){ return p.txt; }).join(sep);

function esc(s){ return s.split("&").join("&amp;").split("<").join("&lt;").split(">").join("&gt;"); }
function boldify(s){ const a = s.split("**"); let r = ""; for (let i = 0; i < a.length; i++){ r += (i % 2 === 1) ? ("<strong>" + a[i] + "</strong>") : a[i]; } return r; }
const lines = reportMarkdown.split(NL);
const htmlParts = []; let inList = false;
function closeList(){ if (inList) { htmlParts.push("</ul>"); inList = false; } }
for (let i = 0; i < lines.length; i++) {
  const ln = lines[i];
  const t = ln.trim();
  if (t.length === 0) { closeList(); continue; }
  if (ln.charAt(0) === "<") { closeList(); htmlParts.push(ln); continue; }
  if (t === "---") { closeList(); htmlParts.push("<hr>"); continue; }
  if (ln.indexOf("### ") === 0) { closeList(); htmlParts.push("<h3>" + boldify(esc(ln.slice(4))) + "</h3>"); continue; }
  if (ln.indexOf("## ") === 0) { closeList(); htmlParts.push("<h2>" + boldify(esc(ln.slice(3))) + "</h2>"); continue; }
  if (ln.indexOf("# ") === 0) { closeList(); htmlParts.push("<h1>" + boldify(esc(ln.slice(2))) + "</h1>"); continue; }
  if (ln.indexOf("- ") === 0 || ln.indexOf("* ") === 0) { if (!inList) { htmlParts.push("<ul>"); inList = true; } htmlParts.push("<li>" + boldify(esc(ln.slice(2))) + "</li>"); continue; }
  closeList(); htmlParts.push("<p>" + boldify(esc(ln)) + "</p>");
}
closeList();
const style = "<style>body{font-family:-apple-system,'Segoe UI','Microsoft YaHei',sans-serif;max-width:900px;margin:24px auto;padding:0 16px;line-height:1.7;color:#222}img{max-width:100%;height:auto;display:block;margin:10px 0}h1{font-size:24px}h2{font-size:20px;border-bottom:1px solid #eee;padding-bottom:4px}h3{font-size:16px;color:#0a58ca}hr{border:none;border-top:1px solid #ddd;margin:28px 0}</style>";
const htmlReport = '<!doctype html><html><head><meta charset="utf-8">' + style + '</head><body>' + htmlParts.join(NL) + '</body></html>';
return [{ json: { reportMarkdown: reportMarkdown, htmlReport: htmlReport, paperCount: parts.length } }];
